sql:
SELECT psnr_value
FROM psnr_values
WHERE result_id = 1;

SELECT compression_ratio
  FROM compression_results
  WHERE compression_quality = 'High';

SELECT total_file_size
FROM file_sizes
WHERE result_id = 0;

SELECT mse, psnr, compression_ratio
FROM compression_results
WHERE result_id = 1;

SELECT AVG(compression_ratio) AS avg_compression_ratio
FROM compression_results
WHERE compression_quality = 'High';

SELECT quality_value
FROM qualities
WHERE quality_value = 100;

SELECT image_name 
FROM images 
ORDER BY upload_date, image_name;

external_knowledge:
; The term "top 10 most frequently accessed images" refers to the images with the highest number of access events in the access logs; 
; The "compression settings" include quality, k-value, algorithm name, and compression quality; 
; The "quality metrics" include mean squared error (MSE), peak signal-to-noise ratio (PSNR), and compression ratio; 
; The "user information" includes user name, email, role, access date, and access type.

sql:
SELECT AVG(compression_duration) AS average_duration
FROM compression_settings
WHERE quality = 100;
